queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?stylename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:styleId ?cg . ?child a :Styles ; p:id ?cg . ?l p:photographerId ?pg . ?parent a :Photographers ; p:id ?pg . } GROUP BY ?child }
  ?child p:styleName ?stylename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photographers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?stylename WHERE {
  ?photographers_styles a :Photographers_Styles .
  ?styles a :Styles .
  ?photographers_styles p:hasStyles ?styles .
  ?photographers a :Photographers .
  ?photographers_styles p:hasPhotographers ?photographers .
  ?photographers p:name ?name .
  ?styles p:styleName ?stylename .
} }
  collective: { SELECT ?stylename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:styleId ?cg . ?child a :Styles ; p:id ?cg . ?l p:photographerId ?pg . ?parent a :Photographers ; p:id ?pg . } GROUP BY ?child }
  ?child p:styleName ?stylename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photographers } }
  FILTER(?nf = ?total)
} }
}
